import React, { useEffect, useState } from 'react';
import axios from 'axios';

function ListaDisciplinas({ reloadKey, onEditar }) {
  const [disciplinas, setDisciplinas] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/disciplinas')
      .then((res) => {
        setDisciplinas(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar disciplinas:', err);
        setCarregando(false);
      });
  }, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar esta disciplina?')) {
      axios.delete(`/api/disciplinas/${id}`)
        .then(() => {
          setDisciplinas(disciplinas.filter(d => d.id !== id));
        })
        .catch(() => alert('Erro ao deletar disciplina'));
    }
  };

  if (carregando) return <p>Carregando disciplinas...</p>;
  if (disciplinas.length === 0) return <p>Nenhuma disciplina cadastrada.</p>;

  return (
  <div className="mt-4">
  <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">Lista de Disciplinas</h2>
  {/* Cabeçalho de colunas */}
  <div className="flex px-5 pb-2 text-gray-500 font-bold text-sm">
    <div className="w-1/3">Disciplina</div>
    <div className="w-1/3">Período</div>
    <div className="w-1/6">Turno</div>
    <div className="w-1/6 text-right">Ações</div>
  </div>
  {/* Lista em cards */}
  <ul className="space-y-3">
    {disciplinas.map((d) => (
      <li
        key={d.id}
        className="flex items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
      >
        <div className="w-1/3 font-medium text-gray-800 truncate">{d.nome}</div>
        <div className="w-1/3 text-gray-500">{d.periodo_nome}</div>
        <div className="w-1/6 text-gray-500">{d.turno}</div>
        <div className="w-1/6 flex justify-end space-x-2">
          <button
            onClick={() => onEditar(d)}
            className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
          >
            Editar
          </button>
          <button
            onClick={() => handleDeletar(d.id)}
            className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
          >
            Deletar
          </button>
        </div>
      </li>
    ))}
  </ul>
</div>


  );
}

export default ListaDisciplinas;
